/**
 * Custom hooks for notification preferences.
 * Wraps auto-generated Orval hooks with additional logic and type safety.
 */
import { useCallback } from 'react';

import { useQueryClient } from '@tanstack/react-query';

import {
  useNotificationWebPreferencesGet,
  useNotificationWebPreferencesUpdate,
  getNotificationWebPreferencesGetQueryKey,
} from '../../../server/autoGeneratedHooks/notification/notifications/notifications';
import { isValueDefined } from '../../../utils/is';

import type { NotificationPreferences, CategoryPreference } from './types';
import type { DisplayPreference } from '../../../server/autoGeneratedHooks/notification/models';

const DEFAULT_DISPLAY: DisplayPreference = 3;
const DISPLAY_NONE: DisplayPreference = 0;

interface ApiPreferencesData {
  notificationsEnabled?: boolean;
  quietHoursEnabled?: boolean;
  quietHoursStart?: string | null;
  quietHoursEnd?: string | null;
  quietHoursTimezone?: string | null;
  questionnaireSubmittedDisplay?: DisplayPreference;
  templateUpdatedDisplay?: DisplayPreference;
  userInvitedDisplay?: DisplayPreference;
  menuUpdatedDisplay?: DisplayPreference;
  paymentDueDisplay?: DisplayPreference;
}

function createCategoryPref(display?: DisplayPreference): CategoryPreference {
  return { enabled: display !== DISPLAY_NONE, displayPreference: display ?? DEFAULT_DISPLAY };
}

function transformToPreferences(data: ApiPreferencesData): NotificationPreferences {
  return {
    notificationsEnabled: data.notificationsEnabled ?? true,
    quietHoursEnabled: data.quietHoursEnabled ?? false,
    quietHoursStart: data.quietHoursStart ?? null,
    quietHoursEnd: data.quietHoursEnd ?? null,
    quietHoursTimezone: data.quietHoursTimezone ?? null,
    categoryPreferences: {
      questionnaireSubmitted: createCategoryPref(data.questionnaireSubmittedDisplay),
      templateUpdated: createCategoryPref(data.templateUpdatedDisplay),
      userInvited: createCategoryPref(data.userInvitedDisplay),
      menuUpdated: createCategoryPref(data.menuUpdatedDisplay),
      paymentDue: createCategoryPref(data.paymentDueDisplay),
    },
  };
}

function getDisplay(cat: CategoryPreference): DisplayPreference {
  return cat.enabled ? cat.displayPreference : DISPLAY_NONE;
}

function transformToRequest(prefs: NotificationPreferences): ApiPreferencesData {
  return {
    notificationsEnabled: prefs.notificationsEnabled,
    quietHoursEnabled: prefs.quietHoursEnabled,
    quietHoursStart: prefs.quietHoursStart,
    quietHoursEnd: prefs.quietHoursEnd,
    quietHoursTimezone: prefs.quietHoursTimezone,
    questionnaireSubmittedDisplay: getDisplay(prefs.categoryPreferences.questionnaireSubmitted),
    templateUpdatedDisplay: getDisplay(prefs.categoryPreferences.templateUpdated),
    userInvitedDisplay: getDisplay(prefs.categoryPreferences.userInvited),
    menuUpdatedDisplay: getDisplay(prefs.categoryPreferences.menuUpdated),
    paymentDueDisplay: getDisplay(prefs.categoryPreferences.paymentDue),
  };
}

interface UseGetPreferencesResult {
  preferences: NotificationPreferences | undefined;
  isLoading: boolean;
  isError: boolean;
  error: Error | null;
}

export function useGetNotificationPreferences(): UseGetPreferencesResult {
  const query = useNotificationWebPreferencesGet();
  const queryError: unknown = query.error;
  return {
    preferences: isValueDefined(query.data) ? transformToPreferences(query.data) : undefined,
    isLoading: query.isLoading,
    isError: query.isError,
    error: queryError instanceof Error ? queryError : null,
  };
}

interface UpdateCallbacks {
  onSuccess?: () => void;
  onError?: (error: Error) => void;
}

interface UseUpdatePreferencesResult {
  updatePreferences: (preferences: NotificationPreferences) => void;
  isPending: boolean;
  isError: boolean;
  isSuccess: boolean;
  error: Error | null;
}

function createMutationConfig(
  queryClient: ReturnType<typeof useQueryClient>,
  callbacks?: UpdateCallbacks
): { onSuccess: () => void; onError: (error: unknown) => void } {
  return {
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: getNotificationWebPreferencesGetQueryKey() }).catch(() => {});
      callbacks?.onSuccess?.();
    },
    onError: (error: unknown) => {
      const errorObj = error instanceof Error ? error : new Error('Update failed');
      callbacks?.onError?.(errorObj);
    },
  };
}

export function useUpdateNotificationPreferences(callbacks?: UpdateCallbacks): UseUpdatePreferencesResult {
  const queryClient = useQueryClient();
  const mutation = useNotificationWebPreferencesUpdate({
    mutation: createMutationConfig(queryClient, callbacks),
  });
  const updatePreferences = useCallback(
    (preferences: NotificationPreferences) => mutation.mutate({ data: transformToRequest(preferences) }),
    [mutation]
  );
  const mutationError: unknown = mutation.error;
  return {
    updatePreferences,
    isPending: mutation.isPending,
    isError: mutation.isError,
    isSuccess: mutation.isSuccess,
    error: mutationError instanceof Error ? mutationError : null,
  };
}
